export const addSchemaColumns = async (
  firstItem: object,
  projectRelativePath: string,
) => {
  console.log("updateSchemaColumns", { projectRelativePath });

  if (!projectRoot) {
    return;
  }
  // NB: ensure to
  // for now, take it from the first row
  const newPropertiesKeys = Object.keys(firstItem).filter(
    (key) => key !== "__actionSchemaId",
  );
  const schemaPath = getAbsoluteSchemaPath(projectRelativePath);

  await lockAction(schemaPath, async () => {
    const schema = await readJsonFile<CapableJsonSchema>(schemaPath);
    if (!schema) {
      return;
    }

    const alreadyProperties = getCapableJsonSchemaProperties(schema) || {};
    const alreadyPropertiesKeys = Object.keys(alreadyProperties);
    const newPropertiesNotYet = newPropertiesKeys.filter(
      (key) => !alreadyPropertiesKeys.includes(key),
    );

    if (newPropertiesNotYet.length === 0) {
      return;
    }

    const newPropertiesObject = mergeObjectsArray(
      newPropertiesNotYet.map((key) => ({
        [key]: { type: "string" } as CapableJsonSchema,
      })),
    );
    const newProperties = { ...alreadyProperties, ...newPropertiesObject };
    const newSchema = schema as MainCapableJsonSchema;
    newSchema.properties.items = {
      ...newSchema.properties.items,
      items: {
        ...newSchema.properties.items.items,
        type: "object",
        properties: newProperties,
      },
    };
    return writeJsonToFile(schemaPath, newSchema);
  });
};

const updateCreationPlugin = (url: string) => (x: CapableJsonSchemaPlugin) => {
  if (!x.$openapi) {
    return x;
  }

  const $openapi: PluginOpenapiDetails = {
    ...x.$openapi,
    url,
  };

  return { ...x, $openapi };
};

const migrateActionSchemaUrls = async () => {
  // Migrate all existing `persons/[x]/files/[y]/y.schema.json` so all plugins point to `api.actionschema.com/openapi.json` or `localhost:42000/openapi.json`

  const personSlugs = (await get("Person")).result?.map((x) => x.slug) || [];
  const projectSchemaPaths = personSlugs
    .map((slug) => {
      const filesFolder = path.join(
        projectRoot,
        "memory",
        "persons",
        slug,
        "files",
      );
      if (!fs.existsSync(filesFolder)) {
        return [];
      }

      const projectSchemaPaths = fs
        .readdirSync(filesFolder)
        .map((name) => path.join(filesFolder, name, `${name}.schema.json`))
        .filter((p) => fs.existsSync(p));

      return projectSchemaPaths;
    })
    .flat();

  // for each project, go into the schema and update the $openapi
  oneByOne(projectSchemaPaths, async (p, i) => {
    console.log(`${i + 1}/${projectSchemaPaths.length}`);
    const schema = await readJsonFile<MainCapableJsonSchema>(p);

    if (
      !schema ||
      !schema.properties ||
      !schema.properties.items ||
      !schema.properties.items.items
    ) {
      return;
    }

    const url = !!argument
      ? "http://api.actionschema.com/openapi.json"
      : "http://localhost:42000/openapi.json";

    schema.properties.items.creationPlugins =
      schema.properties.items.creationPlugins?.map(updateCreationPlugin(url));

    schema.properties.items.items.properties = objectMapSync(
      schema.properties.items.items.properties,
      (key, value) => {
        const newCreationPlugins = value.creationPlugins?.map(
          updateCreationPlugin(url),
        );
        return { ...value, creationPlugins: newCreationPlugins };
      },
    );

    // if there, ensure to replace openapi of all of them

    await writeJsonToFile(p, schema);
    // console.dir({ schema }, { depth: 99 });
  });
};

export const conditionalDestination = async (
  context: StandardContext & {
    /** the (case-senstive) name of the table you want to push this row to if the condition is met */
    destinationTableName?: string;

    /** Automatically provided */
    row?: O;

    /** Automatically provided  */
    previousResult?: ConditionalDestinationResult | undefined;
  },
): Promise<StandardResponse & { result?: ConditionalDestinationResult }> => {
  const { row, destinationTableName, previousResult, ...standardContext } =
    context;

  if (!row) {
    return { isSuccessful: false, message: "Invalid input" };
  }

  if (!standardContext.me_personSlug) {
    return { isSuccessful: false, message: "Please login" };
  }

  const projectRelativePath = `memory/persons/${standardContext.me_personSlug}/files/${destinationTableName}/${destinationTableName}.mdb`;
  const dbPath = path.join(projectRoot, projectRelativePath);

  // find the table

  if (
    !fs.existsSync(dbPath) ||
    !(
      await getSimpleFsAuthorization({
        ...standardContext,
        projectRelativePath,
      })
    ).canWrite
  ) {
    return { isSuccessful: false, message: "Table not found", priceCredit: 0 };
  }

  // insert

  const { result: rowIds } = await actionSchemaCreate({
    ...standardContext,
    // NB: overwrite the id to either undefined or an id of the table it is sent to
    items: [{ ...row, __actionSchemaId: previousResult?.id }],
    projectRelativePath,
    shouldExecuteGridEntireRow: false,
    totalPriceCredit: 0,
  });

  const id = rowIds?.[0];

  if (!id) {
    return {
      isSuccessful: true,
      message: "Condition met, insertion failed",
      priceCredit: 0,
    };
  }

  return {
    isSuccessful: true,
    message: "Condition met and inserted",
    priceCredit: 0,
    result: { id },
  };
};

export const getKeyFromObject = (
  object: { [key: string]: any },
  location: string,
): any => {
  const chunks = location
    .replaceAll("]", "")
    .split(".")
    .map((x) => x.split("["))
    .flat();

  // console.log(chunks);

  return chunks.reduce((previous, current) => {
    if (previous === undefined) {
      return undefined;
    }

    if (
      !isNaN(Number(current)) &&
      !Array.isArray(previous) &&
      !previous[current]
    ) {
      // NB: special case: we specified a number on an object but that key doesn't exist on the object
      // Assuming we mean the n-th key of the object, we return that instead.
      const keys = Object.keys(previous);
      const nKeyValue = previous[keys[Number(current)]];
      return nKeyValue;
    }

    return previous[current];
  }, object);

export const getKeyFromObjectPlugin = (context: {
  objectString: string;
  location: string;
}) => {
  const { location, objectString } = context;

  //  console.log({ objectString, location });
  const object = tryParseJson<O>(objectString);

  if (object === null || typeof object !== "object") {
    return { isSuccessful: false, message: "No object found" };
  }

  const result = getKeyFromObject(object, location);

  if (result === null || result === undefined) {
    return { isSuccessful: false, message: "Location not found" };
  }

  return { isSuccessful: true, result };

