export const getSchema = async (
  context: StandardContext & { projectRelativePath?: string },
): Promise<
  StandardResponse & {
    schema?: CapableJsonSchema | null;
    canWrite?: boolean;
  }
> => {
  const { projectRelativePath } = context;

  if (!projectRelativePath || !projectRoot) {
    return { isSuccessful: false, message: "Invalid file" };
  }

  const dbPath = path.join(projectRoot, projectRelativePath);
  const folderPath = path.parse(dbPath).dir;
  const schemaFilename = `./${path.parse(dbPath).name}.schema.json`;

  const absoluteSchemaPath = path.join(folderPath, schemaFilename);

  if (!fs.existsSync(absoluteSchemaPath)) {
    return { isSuccessful: false, message: "Invalid file" };
  }

  // ensure we are authorized
  const authorization = await getMdbAuthorization(context);

  if (!authorization.canRead) {
    console.log({ dbPath, authorization, context });
    return { isSuccessful: false, message: "Can't get file" };
  }

  const schema = await readJsonFile<CapableJsonSchema>(absoluteSchemaPath);

  return {
    isSuccessful: true,
    message: "Found schema",
    schema,
    canWrite: authorization.canWrite,
  };
};

export const moveObjectKeyToIndex = <T extends O>(
  object: T,
  key: string,
  toIndex: number,
) => {
  const keys = Object.keys(object);
  const currentKeyIndex = keys.findIndex((x) => x === key);

  if (currentKeyIndex === -1) {
    return;
  }

  const beforeKeys = keys.slice(0, currentKeyIndex);
  const afterKeys = keys.slice(currentKeyIndex + 1);

  const newKeys = beforeKeys.concat(afterKeys);

  //  console.log({ newKeys });
  const newBeforeKeys = newKeys.slice(0, toIndex);
  const newAfterKeys = newKeys.slice(toIndex);
  const finalKeys = newBeforeKeys.concat([key, ...newAfterKeys]);

  //  console.log({ finalKeys });

  const newObject = mergeObjectsArray(
    finalKeys.map((k) => {
      return { [k]: object[k] };
    }),
  );

  //console.log({ newObject });

  return newObject;
};

export const getCompleteContext = (context: {
  row: O;
  pluginContext: O | undefined;
  propertyKey: string;
  projectRelativePath: string;
}) => {
  const { pluginContext, propertyKey, row, projectRelativePath } = context;

  const newPluginContext = pluginContext ? { ...pluginContext } : {};

  Object.keys(newPluginContext).map((key) => {
    if (typeof newPluginContext[key] === "string") {
      newPluginContext[key] = replaceVariables(newPluginContext[key], row);
    }
  });

  const standardPluginContext: StandardPluginContext = {
    row,
    previousResult: row[propertyKey],
    // NB: always overwrites this
    projectRelativeGridPath: projectRelativePath,
  };

  // NB: Here it always provides certain default keys for context.
  const completeContext = {
    ...newPluginContext,
    // ...standardContext,
    ...standardPluginContext,
  };

  return completeContext;
};

