export const executeGridEntireRowRecursive = async (
  context: StandardContext & ExecuteGridEntireRowContext,
  properties: {
    [key: string]: CapableJsonSchema;
  },
  done: string[],
  started: string[],
): Promise<number> => {
  const priceCreditArray = await Promise.all(
    getObjectKeysArray(properties).map(async (key) => {
      const isStarted = started.includes(key);

      if (isStarted) {
        // base case to skip
        return 0;
      }

      const value = properties[key];
      const firstPlugin = value.creationPlugins?.[0];

      if (!firstPlugin) {
        // base case: no plugin so it's done
        started.push(key);
        done.push(key);
        console.log("no plugin", key);
        return 0;
      }

      const propertyDependencies = firstPlugin.propertyDependencies || [];

      const areRequirementsMet = propertyDependencies.every((k) =>
        done.includes(k),
      );

      // console.log({ key, areRequirementsMet });

      if (!areRequirementsMet) {
        // base case don't do it, we'll handle in a recursion
        return 0;
      }

      started.push(key);

      // NB: we need to wait!
      const result = await executeGridPlugin({
        ...context,
        propertyKey: key,
        waitForResult: true,
      });

      done.push(key);

      // Recursion case
      const recursion = await executeGridEntireRowRecursive(
        context,
        properties,
        done,
        started,
      );

      const priceCredit = (result.priceCredit || 0) + recursion;
      return priceCredit;
    }),
  );

  const priceCredit = sum(priceCreditArray);

  return priceCredit;
};

export const getMdbAuthorization = async (
  context: StandardContext & {
    projectRelativePath?: string;
    isDebug?: boolean;
  },
): Promise<{ canRead: boolean; canWrite: boolean }> => {
  // 2) get the `projectRelativeFolderPath`
  const { projectRelativePath, isDebug, me_personSlug } = context;
  if (!projectRoot || !projectRelativePath) {
    return { canRead: false, canWrite: false };
  }

  const { person } = await getPerson(context);

  // NB: Should be attached in functionContext for any logged in user.
  const isAdmin = !me_personSlug
    ? false
    : (
        await get("Group", { slug: "admin" })
      ).result?.[0]?.personSlugs?.includes(me_personSlug);

  if (isAdmin) {
    return { canRead: true, canWrite: true };
  }

  // 1) Get the paths that this user can r/w
  const projectRelativeBasePathArray = await getExplorableBasePaths(context);

  // NB: Find the basefolder path that is applicable
  const projectRelativeBaseFolderPath =
    projectRelativeBasePathArray.find(
      (p) =>
        // NB: the "/" is super important to ensure it's the end of the folder
        projectRelativePath === p.projectRelativePath ||
        projectRelativePath.startsWith(p.projectRelativePath + "/"),
    )?.projectRelativePath || "";

  if (!projectRelativeBaseFolderPath) {
    // it's not in our base folder, so only if we specify privacy in the object
    // if privacy is public/unlisted, canRead is true

    const db = projectRelativePath.endsWith(".mdb")
      ? makeActionSchemaDb(projectRelativePath)
      : undefined;
    const privacy = db?.get("privacy");
    const canRead = privacy === "unlisted" || privacy === "public";

    return { canRead, canWrite: false };
  }

  // if (!projectRelativeBaseFolderPath) {
  //   return { canRead: false, canWrite: false };
  // }

  const isPersonOrGroupFile =
    (projectRelativePath.startsWith("memory/persons/") &&
      projectRelativePath.endsWith("/person.json")) ||
    (projectRelativePath.startsWith("memory/groups/") &&
      projectRelativePath.endsWith("/group.json"));

  return { canRead: true, canWrite: !isPersonOrGroupFile };
};

