const generatePropertiesIfPossibleRecursive = async (
  properties: RowProto,
  done: string[],
  started: string[],
): Promise<number> => {
  const priceCreditArray = await Promise.all(
    getObjectKeysArray(properties).map(async (key) => {
      const isStarted = started.includes(key);

      if (isStarted) {
        // base case to skip
        return 0;
      }

      const value = properties[key];
      const areRequirementsMet = value.requiredProperties.every((k) =>
        done.includes(k),
      );

      if (!areRequirementsMet) {
        // base case don't do it, we'll handle in a recursion
        return 0;
      }

      const fnKey = value.functionName as keyof typeof functions;
      const fn = functions[fnKey];
      started.push(key);
      const result = await fn(key);
      done.push(key);

      // recursion case
      const recursion = await generatePropertiesIfPossibleRecursive(
        properties,
        done,
        started,
      );
      const priceCredit = (result.priceCredit || 0) + recursion;
      return priceCredit;
    }),
  );

  const priceCredit = sum(priceCreditArray);

  return priceCredit;
};

